## Rewritten Code

```javascript
var TWO_PI = 6.283;
var GOLDEN_RATIO = 1.618;
var SQRT_HALF = 0.707;

var physicsConfig = {
  attraction: 4000,
  springCoeff: 0.004,
  amplification: 0.92,
  gravity: 0.0003,
  streamMax: 40,
  streamDecay: 0.04,
  theta: 0.06
};

var nodeHub = { id: 'hub', label: 'Hub', r: 26, x: 400, y: 300, vx: 0, vy: 0 };
var nodeAlpha = { id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 };
var nodeBeta = { id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 };
var nodeGamma = { id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 };
var nodeDelta = { id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 };
var nodeEpsilon = { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 };

var nodes = [nodeHub, nodeAlpha, nodeBeta, nodeGamma, nodeDelta, nodeEpsilon];

var springs = [
  { a: 'hub', b: 'alpha', rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta', rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma', rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta', rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta', rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

var currentCamera = { x: 400, y: 300, zoom: 1 };
var targetCamera = { x: 400, y: 300, zoom: 1 };
var particles = [];
var tickCount = 0;

function findNodeById(nodeId) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === nodeId) return nodes[i];
  }
  return null;
}

function applyForces() {
  // Coulomb repulsion between all node pairs
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var distance = Math.sqrt(dx * dx + dy * dy) || 1;
      var repulsiveForce = physicsConfig.attraction / (distance * distance);
      var forceX = (dx / distance) * repulsiveForce;
      var forceY = (dy / distance) * repulsiveForce;

      nodes[i].vx += forceX;
      nodes[i].vy += forceY;
      nodes[j].vx -= forceX;
      nodes[j].vy -= forceY;
    }
  }

  // Hooke's law spring forces along edges
  for (var s = 0; s < springs.length; s++) {
    var nodeA = findNodeById(springs[s].a);
    var nodeB = findNodeById(springs[s].b);
    if (!nodeA || !nodeB) continue;

    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var distance = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = distance - springs[s].rest;
    var springForce = (springs[s].k || physicsConfig.springCoeff) * displacement;

    nodeA.vx += (dx / distance) * springForce;
    nodeA.vy += (dy / distance) * springForce;
    nodeB.vx -= (dx / distance) * springForce;
    nodeB.vy -= (dy / distance) * springForce;
  }

  // Integrate velocity and apply centering gravity + velocity damping
  for (var n = 0; n < nodes.length; n++) {
    // Centering gravity toward (400, 300)
    nodes[n].vx += (400 - nodes[n].x) * physicsConfig.gravity;
    nodes[n].vy += (300 - nodes[n].y) * physicsConfig.gravity;

    // Velocity damping (amplification < 1 acts as friction)
    nodes[n].vx *= physicsConfig.amplification;
    nodes[n].vy *= physicsConfig.amplification;

    // Position integration
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

function spawnParticle() {
  if (particles.length >= physicsConfig.streamMax) return;

  var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TWO_PI;
  var speed = 0.3 + Math.random() * SQRT_HALF;

  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * GOLDEN_RATIO) * SQRT_HALF
  });
}

function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var particle = particles[i];
    particle.age++;

    // Remove expired particles
    if (particle.age > particle.maxAge) {
      particles.splice(i, 1);
      continue;
    }

    // Apply drag/decay to particle velocity
    var dragFactor = 1 - physicsConfig.streamDecay * 0.125;
    particle.vx *= dragFactor;
    particle.vy *= dragFactor;

    // Position integration
    particle.x += particle.vx;
    particle.y += particle.vy;
  }
}

function interpolateCamera() {
  currentCamera.x += (targetCamera.x - currentCamera.x) * physicsConfig.theta;
  currentCamera.y += (targetCamera.y - currentCamera.y) * physicsConfig.theta;
  currentCamera.zoom += (targetCamera.zoom - currentCamera.zoom) * physicsConfig.theta;
}

function simulationTick() {
  applyForces();
  updateParticles();
  interpolateCamera();

  if (tickCount % 3 === 0) spawnParticle();
  tickCount++;
}

setInterval(simulationTick, 16);
```

## Summary

This is a **force-directed graph layout simulation** with:

1. **`applyForces`** — Computes Coulomb-like repulsion between all node pairs and Hooke's law spring attraction along edges, applies centering gravity toward (400,300), damps velocities, and integrates positions.
2. **`spawnParticle`** — Emits particles from random nodes with random velocity at random angles.
3. **`updateParticles`** — Ages particles, applies drag, integrates positions, and removes expired ones.
4. **`interpolateCamera`** — Smoothly lerps camera position/zoom toward a target using the `theta` easing factor.
5. **`simulationTick`** — Main loop running at ~60fps (16ms interval), spawning a particle every 3rd tick.
